INSERT INTO `categories` (`id`, `name`, `description`, `image`, `is_active`, `created_date`) VALUES
(1, 'Anklet', 'Discover our exquisite collection of sterling silver anklets, crafted with precision and elegance for those seeking to elevate their leg jewellery with timeless style. From delicate chains to ornamental designs, our anklets are perfect for adding a subtle sparkle to any occasion, whether for everyday wear or special celebrations.', '/images/categories/anklet.jpg', 1, '2024-01-01'),
(2, 'Bangle', 'Discover our exquisite collection of silver bangles, expertly crafted to add timeless elegance to any wrist. From delicate minimalist designs to ornate statement pieces, our bangles appeal to those seeking versatile, high-quality silver jewellery that seamlessly transitions from everyday wear to special occasions.', '/images/categories/bangle.jpg', 1, '2024-01-01'),
(3, 'Bracelet', 'Discover our exquisite collection of sterling silver bracelets, featuring timeless designs from delicate chains to bold statement pieces that elevate any occasion. Perfect for those seeking sophisticated, versatile jewelry that complements both everyday style and special moments.', '/images/categories/bracelet.jpg', 1, '2024-01-01'),
(4, 'Brooch', 'Discover our exquisite collection of silver brooches, timeless pieces that add sophistication and elegance to any ensemble. Crafted with meticulous attention to detail, our brooches appeal to discerning jewelry enthusiasts and fashion-forward individuals seeking to elevate their style with versatile, statement-making accessories.', '/images/categories/brooch.jpg', 1, '2024-01-01'),
(5, 'Chain', 'Discover our exquisite collection of sterling silver chains, crafted to elevate any look with timeless elegance and versatility. From delicate, minimalist designs to bold statement pieces, our chains appeal to jewelry enthusiasts seeking quality craftsmanship and the perfect foundation for layering or wearing solo.', '/images/categories/chain.jpg', 1, '2024-01-01'),
(6, 'Cufflink', 'Elevate your formal attire with our exquisite collection of silver cufflinks, expertly crafted to add sophistication and polish to any gentleman''s wardrobe. From classic designs to contemporary styles, our cufflinks appeal to discerning professionals and those seeking timeless accessories that make a refined statement.', '/images/categories/cufflink.jpg', 1, '2024-01-01'),
(7, 'Earring', 'Discover our exquisite collection of silver earrings, crafted to elevate any style from casual to sophisticated. Each piece combines timeless elegance with contemporary design, perfect for those who appreciate quality craftsmanship and versatile accessories that complement every occasion.', '/images/categories/earring.jpg', 1, '2024-01-01'),
(8, 'Hair Pin', 'Elevate your everyday style with our exquisite collection of silver hair pins, crafted to add a touch of sophisticated elegance to any hairstyle. Perfect for both minimalist and ornate tastes, these versatile accessories appeal to anyone seeking timeless beauty and refined craftsmanship in their personal grooming.', '/images/categories/hair-pin.jpg', 1, '2024-01-01'),
(9, 'Necklace', 'Discover our exquisite collection of sterling silver necklaces, featuring timeless designs from delicate chains to statement pieces that complement any occasion. Perfect for those who appreciate refined elegance, each necklace combines craftsmanship with versatility, making it an essential accessory for everyday wear or special moments.', '/images/categories/necklace.jpg', 1, '2024-01-01'),
(10, 'Nose Pin', 'Discover our exquisite collection of silver nose pins, featuring delicate designs from traditional studs to modern artistic pieces crafted from premium sterling silver. Perfect for anyone seeking elegant, versatile adornments that add a touch of sophistication to any occasion.', '/images/categories/nose-pin.jpg', 1, '2024-01-01'),
(11, 'Pendant', 'Elegant silver pendants designed to complement any style, from delicate minimalist pieces to bold statement designs. Perfect for those seeking timeless jewelry that adds sophistication to everyday wear or special occasions.', '/images/categories/pendant.jpg', 1, '2024-01-01'),
(12, 'Ring', 'Discover our exquisite collection of sterling silver rings, expertly crafted to complement any occasion—from timeless classics to contemporary designs. Perfect for those seeking elegant, versatile pieces that blend sophistication with quality craftsmanship.', '/images/categories/ring.jpg', 1, '2024-01-01'),
(13, 'Toe Ring', 'Discover our exquisite collection of sterling silver toe rings, designed to add a delicate touch of elegance to your feet. Perfect for beach lovers, bohemian style enthusiasts, and anyone seeking to express their individuality with understated, timeless jewellery.', '/images/categories/toe-ring.jpg', 1, '2024-01-01');
INSERT INTO `products` (`id`, `sku`, `name`, `category`, `description`, `price`, `weight_grams`, `purity`, `image`, `is_active`, `stock_quantity`, `created_date`, `category_id`) VALUES
(1, 'SLV-BRC-001', 'Silver Cuff Bracelet', 'Bracelet', 'Elevate your style with our exquisite 925 Sterling Silver Cuff Bracelet, a timeless piece crafted with meticulous attention to detail and superior silverwork that reflects authentic Indian jewellery tradition. This versatile cuff design seamlessly transitions from casual everyday wear to festive celebrations and formal occasions, making it a must-have addition to your jewellery collection. Each bracelet showcases the lustrous beauty and durability of premium sterling silver, ensuring a piece you''ll treasure for generations to come.', 3133.9, 35, '925 Sterling Silver', '/images/products/silver-bracelet-cuff-001.jpg', 1, 83, '2024-01-04', 3),
(2, 'SLV-PND-008', 'Silver Floral Pendant', 'Pendant', 'Introducing our exquisite Silver Floral Pendant, meticulously crafted from premium 925 Sterling Silver that combines timeless elegance with contemporary design. This delicate floral-inspired piece features intricate detailing and superior craftsmanship, making it the perfect accessory for festive celebrations, weddings, daily wear, and traditional occasions. Each pendant showcases the finest quality silver work, reflecting the rich heritage of Indian jewellery artistry while offering a versatile piece that complements both ethnic and modern wardrobes.', 4425.78, 5.3, '925 Sterling Silver', '/images/products/silver-pendant-floral-008.jpg', 1, 50, '2024-01-08', 11),
(3, 'SLV-BRH-005', 'Silver Filigree Brooch', 'Brooch', 'Elevate your traditional and contemporary style with our exquisite Silver Filigree Brooch, meticulously crafted from premium 925 Sterling Silver. This stunning piece showcases intricate filigree detailing that reflects centuries of fine Indian jewellery craftsmanship, making it the perfect accessory for weddings, festivals, and everyday elegance. Whether you''re adorning a saree, kurti, or formal attire, this versatile brooch is a timeless investment that adds a touch of sophistication and cultural grace to any occasion.', 1160.59, 8.57, '925 Sterling Silver', '/images/products/silver-brooch-filigree-005.jpg', 1, 39, '2024-01-09', 4),
(4, 'SLV-BRC-004', 'Silver Tennis Bracelet', 'Bracelet', 'Introducing our exquisite Silver Tennis Bracelet, meticulously crafted from premium 999 Fine Silver that embodies timeless elegance and superior quality. This stunning piece features the classic tennis style with seamlessly aligned stones, making it the perfect accessory for both festive celebrations and everyday sophistication—ideal for weddings, engagements, and special occasions that call for refined grace. Each bracelet is a masterpiece of fine craftsmanship, designed to complement traditional attire and contemporary wear alike, making it a treasured addition to any discerning Indian jewellery collection.', 7448.81, 16.2, '999 Fine Silver', '/images/products/silver-bracelet-tennis-004.jpg', 1, 23, '2024-01-11', 3),
(5, 'SLV-ANK-003', 'Silver Beaded Anklet', 'Anklet', 'Elevate your ethnic style with our exquisite Silver Beaded Anklet, meticulously crafted from 999 Fine Silver that radiates timeless elegance and authenticity. Each delicate bead is expertly strung to create a stunning piece perfect for festivals, weddings, traditional celebrations, and everyday wear, seamlessly complementing both contemporary and traditional ensembles. This heirloom-quality anklet is a testament to fine artisanal craftsmanship, making it an ideal choice for those who appreciate pure silver jewellery with uncompromising quality and grace.', 11783.48, 10.01, '999 Fine Silver', '/images/products/silver-anklet-beaded-003.jpg', 0, 0, '2024-01-13', 1),
(6, 'SLV-BNG-006', 'Silver Plain Polished Bangle', 'Bangle', 'Elevate your everyday elegance with our exquisite Silver Plain Polished Bangle, meticulously crafted from premium 999 Fine Silver to ensure unparalleled purity and lasting brilliance. The sleek, minimalist design features a smooth, mirror-like polished finish that catches light beautifully, making it the perfect accessory for both casual gatherings and festive occasions like weddings, festivals, and celebrations. Versatile and timeless, this bangle seamlessly complements traditional Indian attire as well as modern wardrobe choices, making it an essential addition to every woman''s jewellery collection.', 18731.97, 16.81, '999 Fine Silver', '/images/products/silver-bangle-plain-polished-006.jpg', 1, 54, '2024-01-14', 2),
(7, 'SLV-BRC-009', 'Silver Chain Link Bracelet', 'Bracelet', 'Elevate your everyday elegance with our exquisite Silver Chain Link Bracelet, meticulously crafted from premium 925 Sterling Silver that guarantees lasting brilliance and durability. This versatile piece seamlessly transitions from casual gatherings to formal occasions, making it the perfect addition to any jewellery collection for the modern Indian woman who appreciates authentic craftsmanship. Adorned with interlocking chain links that showcase traditional silversmith artistry, this bracelet embodies timeless sophistication and serves as a stunning statement accessory for weddings, festivals, and everyday wear.', 24729.9, 34.74, '925 Sterling Silver', '/images/products/silver-bracelet-chain-link-009.jpg', 1, 77, '2024-01-15', 3),
(8, 'SLV-NCK-006', 'Silver Statement Collar Necklace', 'Necklace', 'Elevate your elegance with our exquisite Silver Statement Collar Necklace, meticulously crafted from premium 925 Sterling Silver by skilled artisans who blend traditional Indian craftsmanship with contemporary design. This stunning statement piece is the perfect choice for weddings, festivals, and special celebrations, commanding attention with its bold, sophisticated presence that complements both ethnic and modern ensembles. Designed for the discerning Indian woman who appreciates timeless beauty and superior quality, this collar necklace is an investment in luxury that will be cherished for generations to come.', 13754.63, 54.38, '925 Sterling Silver', '/images/products/silver-necklace-statement-collar-006.jpg', 1, 35, '2024-01-19', 9),
(9, 'SLV-NCK-007', 'Silver Lariat Necklace', 'Necklace', 'Elevate your collection with our exquisite Silver Lariat Necklace, meticulously crafted from 925 sterling silver that gleams with timeless elegance and superior quality. This sophisticated lariat style necklace seamlessly transitions from casual gatherings to formal occasions, making it the perfect companion for both everyday wear and special celebrations. Designed with impeccable craftsmanship, this versatile piece embodies the grace of traditional Indian aesthetics while offering contemporary appeal, making it an essential investment for the discerning jewellery connoisseur.', 4393.06, 40.79, '925 Sterling Silver', '/images/products/silver-necklace-lariat-007.jpg', 1, 14, '2024-02-02', 9),
(10, 'SLV-CFL-002', 'Silver Square Cufflink', 'Cufflink', 'Elevate your formal style with our exquisite Silver Square Cufflinks, meticulously crafted from premium 925 Sterling Silver that showcases timeless elegance and superior quality. Perfect for weddings, corporate events, and special occasions, these sophisticated square-design cufflinks add a touch of refined luxury to any formal ensemble. Each piece reflects the finest traditions of Indian silver craftsmanship, blending contemporary design with authentic quality that complements both traditional and modern formal wear.', 5273.48, 12.19, '925 Sterling Silver', '/images/products/silver-cufflink-square-002.jpg', 1, 32, '2024-02-03', 6),
(11, 'SLV-BRC-002', 'Silver Chain Link Bracelet', 'Bracelet', 'Elevate your everyday elegance with our exquisite Silver Chain Link Bracelet, meticulously crafted from premium 925 Sterling Silver that gleams with timeless sophistication. This intricately designed chain link bracelet seamlessly transitions from casual wear to formal occasions, making it an indispensable addition to your jewellery collection for both traditional and contemporary styling. Each piece is a testament to masterful craftsmanship, combining lustrous quality silver with impeccable design that celebrates the rich heritage of Indian jewellery traditions.', 5232.8, 23.28, '925 Sterling Silver', '/images/products/silver-bracelet-chain-link-002.jpg', 1, 32, '2024-02-08', 3),
(12, 'SLV-PND-003', 'Silver Heart Pendant', 'Pendant', 'Radiant Silver Heart Pendant exquisitely crafted from premium 925 Sterling Silver, designed to capture hearts with its timeless elegance and superior shine. This beautifully finished pendant is the perfect embodiment of love and affection, making it an ideal choice for gifting on anniversaries, engagements, or as a cherished symbol of cherished relationships. Celebrate your special moments with a piece of jewellery that combines traditional craftsmanship with contemporary design, ensuring lasting beauty and value for every occasion in life.', 11465.1, 11.54, '925 Sterling Silver', '/images/products/silver-pendant-heart-003.jpg', 1, 74, '2024-02-09', 11),
(13, 'SLV-BNG-002', 'Silver Oxidized Bangle', 'Bangle', 'Experience timeless elegance with our Silver Oxidized Bangle, meticulously crafted from premium 925 Sterling Silver that exudes authentic beauty and durability. This stunning oxidized design showcases exquisite artisanal craftsmanship, perfect for elevating your look at festive occasions, weddings, and everyday celebrations with a touch of traditional Indian sophistication. The rich, darkened silver finish creates an elegant contrast that complements both ethnic and contemporary outfits, making it an essential addition to every jewellery lover''s collection.', 16057.2, 20.37, '925 Sterling Silver', '/images/products/silver-bangle-oxidized-002.jpg', 1, 57, '2024-02-10', 2),
(14, 'SLV-NCK-010', 'Silver Princess Length Necklace', 'Necklace', 'Exquisite Silver Princess Length Necklace, meticulously crafted from 999 Fine Silver to showcase timeless elegance and premium quality. This sophisticated piece is perfect for weddings, festivals, and special celebrations, adding a luminous charm to your traditional and contemporary ensembles alike. Each necklace is a testament to fine artisanal craftsmanship, designed to be a treasured heirloom that complements the grace and beauty of every Indian woman.', 42997.41, 54.54, '999 Fine Silver', '/images/products/silver-necklace-princess-length-010.jpg', 1, 84, '2024-02-14', 9),
(15, 'SLV-NCK-004', 'Silver Layered Necklace', 'Necklace', 'Introducing our exquisite Silver Layered Necklace, meticulously crafted from premium 925 Sterling Silver with impeccable artistry that celebrates timeless elegance. This sophisticated layered design effortlessly transitions from casual everyday wear to special occasions, making it a versatile addition to any jewellery collection. Perfect for the modern Indian woman who appreciates fine craftsmanship and authentic silver jewellery that embodies grace and cultural sophistication.', 47175.35, 35.52, '925 Sterling Silver', '/images/products/silver-necklace-layered-004.jpg', 1, 10, '2024-02-15', 9),
(16, 'SLV-CHN-007', 'Silver Cable Chain', 'Chain', 'Elevate your everyday style with our exquisite Silver Cable Chain, expertly crafted from premium 925 sterling silver for timeless elegance and durability. The interlocking cable design showcases impeccable artisanal craftsmanship, perfect for layering, gifting, or wearing solo at weddings, festivals, and special celebrations. Radiant and versatile, this pure silver chain is an essential addition to every jewellery collection, combining traditional sophistication with contemporary appeal.', 26645.9, 19.52, '925 Sterling Silver', '/images/products/silver-chain-cable-007.jpg', 0, 0, '2024-03-01', 5),
(17, 'SLV-NCK-009', 'Silver Choker Necklace', 'Necklace', 'Elevate your style with our exquisite 925 Sterling Silver Choker Necklace, meticulously crafted to perfection for a timeless, elegant look that complements both traditional and contemporary wardrobes. This premium sterling silver piece features impeccable craftsmanship and lustrous finish, making it an ideal choice for weddings, festive celebrations, casual gatherings, and everyday elegance. Designed for discerning Indian jewellery enthusiasts, this versatile choker is a must-have accessory that adds a touch of sophistication to any occasion.', 11860.08, 47.51, '925 Sterling Silver', '/images/products/silver-necklace-choker-009.jpg', 1, 50, '2024-03-02', 9),
(18, 'SLV-EAR-004', 'Silver Chandelier Earring', 'Earring', 'Experience timeless elegance with our exquisite Silver Chandelier Earrings, meticulously crafted from premium 925 sterling silver to ensure lustrous brilliance and lasting durability. These stunning chandelier-style earrings are versatile enough for everyday wear while making a sophisticated statement at weddings, festivals, and special celebrations. Perfect for those who appreciate authentic Indian jewellery that blends traditional artistry with contemporary design, these earrings showcase superior craftsmanship that adds an enchanting shimmer to any ensemble.', 1730.43, 8.07, '925 Sterling Silver', '/images/products/silver-earring-chandelier-004.jpg', 1, 14, '2024-03-06', 7),
(19, 'SLV-EAR-001', 'Silver Stud Earring', 'Earring', 'Experience timeless elegance with our exquisite Silver Stud Earrings, meticulously crafted from premium 925 Sterling Silver that showcases brilliant lustre and durability. Perfect for both everyday wear and special occasions, these versatile studs complement any ensemble while adding a touch of sophisticated charm to your look. Handcrafted with precision and passion, each pair reflects the finest traditions of Indian jewellery artistry, making them an essential addition to your precious collection.', 27753.47, 6.17, '925 Sterling Silver', '/images/products/silver-earring-stud-001.jpg', 0, 0, '2024-03-09', 7),
(20, 'SLV-CFL-001', 'Silver Classic Round Cufflink', 'Cufflink', 'Exquisitely crafted from premium 950 silver, the Silver Classic Round Cufflink epitomizes timeless elegance and refined sophistication for the modern gentleman. Perfect for formal occasions, business meetings, and festive celebrations, these beautifully designed round cufflinks add a distinguished touch to your traditional and contemporary attire. Each piece is meticulously handcrafted to showcase the lustrous beauty of pure silver, making it an ideal accessory for those who appreciate fine Indian jewellery craftsmanship and impeccable quality.', 9508.85, 14.44, '950 Silver', '/images/products/silver-cufflink-classic-round-001.jpg', 0, 0, '2024-03-17', 6),
(21, 'SLV-CFL-006', 'Silver Bullet Back Cufflink', 'Cufflink', 'Elevate your formal attire with our exquisite Silver Bullet Back Cufflink, meticulously crafted from premium 925 Sterling Silver that showcases impeccable artisanal workmanship and timeless elegance. These sophisticated cufflinks are the perfect accessory for weddings, business meetings, and festive celebrations, adding a refined touch to both traditional and contemporary ensembles. Each piece reflects our commitment to superior craftsmanship and authentic quality, making it an ideal investment for the discerning Indian gentleman who values heritage and style.', 2600.74, 19.8, '925 Sterling Silver', '/images/products/silver-cufflink-bullet-back-006.jpg', 1, 26, '2024-03-17', 6),
(22, 'SLV-BRC-007', 'Silver Hinged Bracelet', 'Bracelet', 'Our exquisite 925 Sterling Silver Hinged Bracelet is a masterpiece of fine craftsmanship, designed with a sophisticated hinged mechanism that combines elegance with comfort for everyday wear and special occasions alike. The premium sterling silver construction ensures brilliance and durability, making it an ideal choice for those who appreciate authentic, high-quality jewellery that complements both traditional and contemporary styles. Perfect for gifting or personal collection, this versatile bracelet adds a touch of timeless charm to weddings, festivals, and everyday moments, resonating with the refined taste of discerning Indian jewellery enthusiasts.', 18284.31, 30.39, '925 Sterling Silver', '/images/products/silver-bracelet-hinged-007.jpg', 1, 76, '2024-03-24', 3),
(23, 'SLV-BNG-007', 'Silver Twisted Bangle', 'Bangle', 'Introducing our exquisite Silver Twisted Bangle, meticulously crafted from premium 950 silver that showcases exceptional purity and timeless elegance. The beautifully twisted design reflects traditional Indian craftsmanship blended with contemporary artistry, making it a versatile accessory perfect for both everyday wear and special occasions like festivals, weddings, and celebrations. Elevate your ethnic and modern wardrobe with this stunning bangle that effortlessly complements both traditional sarees and contemporary outfits, making it an essential addition to every Indian woman''s jewellery collection.', 1573.05, 39.68, '950 Silver', '/images/products/silver-bangle-twisted-007.jpg', 1, 56, '2024-04-07', 2),
(24, 'SLV-TOE-003', 'Silver Flower Toe Ring', 'Toe Ring', 'Introducing our exquisite Silver Flower Toe Ring, meticulously crafted from premium 925 sterling silver to bring timeless elegance to your every step. This beautifully designed piece features intricate floral patterns that capture the essence of traditional Indian craftsmanship, making it the perfect accessory for festivals, weddings, and everyday adornment. Celebrate your personal style with this versatile toe ring that seamlessly blends contemporary aesthetics with classic Indian jewellery traditions.', 956.89, 4.79, '925 Sterling Silver', '/images/products/silver-toe-ring-flower-003.jpg', 1, 43, '2024-04-18', 13),
(25, 'SLV-BRC-003', 'Silver Charm Bracelet', 'Bracelet', 'Elevate your accessory collection with our exquisite Silver Charm Bracelet, meticulously crafted from 999 Fine Silver to ensure superior quality and timeless elegance. This stunning charm bracelet is versatile enough for everyday wear yet sophisticated enough to grace your wrist at weddings, festivals, and special occasions. Perfect for those who appreciate authentic silver craftsmanship, this piece seamlessly blends traditional Indian aesthetic with contemporary design, making it an ideal investment for jewellery enthusiasts seeking both beauty and purity.', 9478.93, 13.87, '999 Fine Silver', '/images/products/silver-bracelet-charm-003.jpg', 0, 0, '2024-04-19', 3),
(26, 'SLV-RNG-009', 'Silver Eternity Band Ring', 'Ring', 'Introducing our exquisite Silver Eternity Band Ring, meticulously crafted from premium 950 silver that epitomizes timeless elegance and superior quality for the discerning Indian jewellery lover. This stunning eternity band features impeccable craftsmanship with a continuous design that symbolizes eternal love and commitment, making it the perfect choice for anniversaries, engagements, weddings, or as a cherished everyday accessory. Adorn your fingers with this sophisticated piece that seamlessly blends traditional Indian jewellery aesthetics with contemporary minimalist design, embodying both grace and enduring beauty.', 16102.94, 12.21, '950 Silver', '/images/products/silver-ring-eternity-band-009.jpg', 1, 69, '2024-05-10', 12),
(27, 'SLV-ANK-005', 'Silver Layered Anklet', 'Anklet', 'Elegant and versatile, our Silver Layered Anklet is meticulously crafted from premium 925 Sterling Silver, showcasing exquisite layered design that catches light beautifully with every step. Perfect for both traditional ceremonies and contemporary everyday wear, this timeless piece adds an understated charm and sophistication to any ensemble. Each anklet is a testament to fine craftsmanship, making it an ideal choice for those who appreciate quality Indian jewellery that seamlessly blends tradition with modern aesthetics.', 4777.66, 15.2, '925 Sterling Silver', '/images/products/silver-anklet-layered-005.jpg', 0, 0, '2024-05-20', 1),
(28, 'SLV-PND-007', 'Silver Geometric Pendant', 'Pendant', 'Elevate your style with our exquisite Silver Geometric Pendant, meticulously crafted from premium 925 Sterling Silver that guarantees timeless elegance and durability. This contemporary geometric design seamlessly blends modern aesthetics with traditional Indian craftsmanship, making it the perfect accessory for everyday wear, festive celebrations, and special occasions. Whether you''re dressing up for a wedding, festival, or casual gathering, this versatile pendant adds a touch of sophistication and artistic flair to any outfit.', 19370.93, 8.17, '925 Sterling Silver', '/images/products/silver-pendant-geometric-007.jpg', 1, 47, '2024-05-27', 11),
(29, 'SLV-BRH-001', 'Silver Floral Brooch', 'Brooch', 'Elevate your traditional and contemporary wardrobe with our exquisite Silver Floral Brooch, meticulously crafted from premium 925 Sterling Silver. This stunning floral design showcases intricate artisanal detailing and timeless elegance, making it the perfect accessory for weddings, festivals, sarees, and everyday occasions. Add a touch of sophistication and grace to any ensemble with this versatile piece that celebrates the finest in Indian jewellery craftsmanship.', 6158.9, 9.25, '925 Sterling Silver', '/images/products/silver-brooch-floral-001.jpg', 1, 30, '2024-05-30', 4),
(30, 'SLV-BRH-006', 'Silver Art Deco Brooch', 'Brooch', 'Elevate your collection with our exquisite Silver Art Deco Brooch, meticulously crafted in premium 925 Sterling Silver that embodies timeless elegance and superior quality. This stunning piece features the iconic geometric patterns and sophisticated lines characteristic of the Art Deco style, making it a perfect accessory for both formal occasions and refined everyday wear. Whether adorning a saree, suit, or dress, this versatile brooch is a treasured addition for those who appreciate fine craftsmanship and enduring beauty—a symbol of refined taste that resonates with the discerning Indian jewellery connoisseur.', 28498.6, 18.7, '925 Sterling Silver', '/images/products/silver-brooch-art-deco-006.jpg', 1, 6, '2024-05-30', 4),
(31, 'SLV-BRC-008', 'Silver Cuff Bracelet', 'Bracelet', 'Introducing our exquisite 925 Sterling Silver Cuff Bracelet, a timeless masterpiece crafted with meticulous attention to detail and unparalleled artisanal excellence. This elegant cuff bracelet showcases the lustrous brilliance of premium sterling silver, making it the perfect accessory for weddings, festivals, and everyday elegance that complements both traditional and contemporary Indian ensembles. Whether adorning your wrist for a special celebration or as a cherished everyday piece, this versatile silver cuff bracelet is a sophisticated investment in quality and style that reflects the rich heritage of Indian jewellery craftsmanship.', 3729.33, 11.67, '925 Sterling Silver', '/images/products/silver-bracelet-cuff-008.jpg', 1, 52, '2024-06-04', 3),
(32, 'SLV-PND-005', 'Silver Om Pendant', 'Pendant', 'Discover the spiritual elegance of our Silver Om Pendant, meticulously crafted in premium 925 Sterling Silver to bring timeless grace to your jewelry collection. This exquisitely designed pendant captures the sacred essence of Om, making it a perfect spiritual companion for daily wear, meditation, or special occasions while showcasing exceptional artisanal craftsmanship. Embrace the divine beauty and authenticity of authentic sterling silver that resonates with tradition, ideal for those seeking meaningful and versatile jewelry that honors their spiritual journey.', 3046.73, 5.93, '925 Sterling Silver', '/images/products/silver-pendant-om-005.jpg', 1, 40, '2024-06-06', 11),
(33, 'SLV-HRP-005', 'Silver Floral Comb Hair Pin', 'Hair Pin', 'Exquisitely crafted from premium 925 Sterling Silver, this elegant floral comb hair pin combines traditional artistry with timeless beauty, making it the perfect accessory for weddings, festivals, and special occasions. Each delicate petal is meticulously sculpted to showcase the finest silver craftsmanship, ensuring a lustrous finish that complements any hairstyle with graceful sophistication. An authentic piece of Indian jewelry that adds a touch of vintage charm and cultural elegance to your everyday look or ceremonial ensemble.', 407.16, 14.38, '925 Sterling Silver', '/images/products/silver-hair-pin-floral-comb-005.jpg', 1, 6, '2024-06-06', 8),
(34, 'SLV-NSP-001', 'Silver Stud Nose Pin', 'Nose Pin', 'Introducing our exquisite Silver Stud Nose Pin, meticulously crafted from 925 Sterling Silver with exceptional purity and brilliant shine. This elegant stud style nose pin seamlessly complements both traditional ethnic wear and contemporary fashion, making it perfect for daily wear, festivals, and special occasions. Our expert artisans have perfected every detail to deliver timeless elegance that captures the essence of Indian jewellery craftsmanship, adding a touch of sophistication to your personal style.', 1018.56, 1.41, '925 Sterling Silver', '/images/products/silver-nose-pin-stud-001.jpg', 1, 50, '2024-06-14', 10),
(35, 'SLV-PND-004', 'Silver Cross Pendant', 'Pendant', 'Introducing our exquisitely crafted Silver Cross Pendant, meticulously made from premium 925 Sterling Silver that embodies timeless elegance and spiritual significance. This beautifully designed cross pendant is perfect for daily wear or special occasions, making it an ideal choice for both personal adornment and meaningful gifting. Each piece reflects superior craftsmanship and authentic silver quality, resonating with the rich traditions of Indian jewellery lovers who appreciate fine, lasting beauty.', 27474.12, 10.33, '925 Sterling Silver', '/images/products/silver-pendant-cross-004.jpg', 1, 30, '2024-06-15', 11),
(36, 'SLV-BNG-003', 'Silver Engraved Bangle', 'Bangle', 'This exquisite 925 Sterling Silver Engraved Bangle showcases masterful craftsmanship with intricate engravings that add timeless elegance to your wrist collection. Crafted from premium grade sterling silver, this versatile bangle seamlessly transitions from everyday sophistication to festive grandeur, making it perfect for weddings, celebrations, and special occasions. With its lustrous finish and detailed artisanal detailing, this piece embodies the finest traditions of Indian silver jewellery, making it an essential addition to every jewellery enthusiast''s treasure box.', 43008.21, 46.43, '925 Sterling Silver', '/images/products/silver-bangle-engraved-003.jpg', 1, 41, '2024-06-22', 2),
(37, 'SLV-CHN-001', 'Silver Figaro Chain', 'Chain', 'Our exquisite Silver Figaro Chain is meticulously crafted from premium 925 Sterling Silver, embodying timeless elegance and superior quality that complements any wardrobe. This beautifully designed chain features the classic Figaro pattern, perfect for everyday wear or special occasions, from casual gatherings to festive celebrations and formal events. Celebrate the rich tradition of fine silver jewellery with a piece that reflects authentic craftsmanship and enduring sophistication, making it an ideal choice for those who appreciate genuine quality and refined style.', 11427.13, 48.63, '925 Sterling Silver', '/images/products/silver-chain-figaro-001.jpg', 1, 67, '2024-06-23', 5),
(38, 'SLV-BRH-003', 'Silver Animal Brooch', 'Brooch', 'Introducing our exquisite Silver Animal Brooch, meticulously crafted from premium 925 Sterling Silver that showcases impeccable artistry and timeless elegance. This stunning piece seamlessly blends traditional Indian jewellery aesthetics with contemporary design, making it the perfect accessory for weddings, festivals, casual outings, and special celebrations. Wear it with pride knowing you''re adorning yourself with authentic, high-quality sterling silver that reflects both sophistication and cultural heritage.', 420.83, 12.49, '925 Sterling Silver', '/images/products/silver-brooch-animal-003.jpg', 1, 79, '2024-06-25', 4),
(39, 'SLV-CFL-003', 'Silver Knot Cufflink', 'Cufflink', 'Introducing our exquisite Silver Knot Cufflink, meticulously crafted from premium 950 silver that epitomizes timeless elegance and superior quality. These beautifully designed cufflinks feature a sophisticated knot motif, perfect for formal occasions, weddings, and festive celebrations, elevating any traditional or contemporary ensemble with a touch of refined luxury. Each piece is a testament to masterful Indian craftsmanship, combining artistic excellence with the enduring allure of pure silver, making it an ideal choice for the discerning gentleman who values both heritage and style.', 10639.27, 9.27, '950 Silver', '/images/products/silver-cufflink-knot-003.jpg', 1, 19, '2024-06-28', 6),
